                  li x25, 0xf4cc2bcf
                  li x26, 0x0
                  li x27, 0xf8831ce3
                  li x29, 0x0
                  li x30, 0xfc6da9b3
                  li x31, 0x80000000
                  la x28, user_stack_end
                  li x25, 0x8ffffffc
                  li x7, 0x0
                  slli x7, x7, 8
                  addi x7, x7, 0x0
                  sw x7, 0(x25)
                  j main
test_done:        
                  li x25, 0x8ffffff8
                  li x7, 0x0
                  slli x7, x7, 8
                  addi x7, x7, 0x1
                  sw x7, 0(x25)
                  ecall

test_fail:        
                  li x25, 0x8ffffff8
                  li x7, 0x1
                  slli x7, x7, 8
                  addi x7, x7, 0x1
                  sw x7, 0(x25)
                  ecall

